function setupPasswordToggle(inputId,toggleId){const toggle=document.getElementById(toggleId);const input=document.getElementById(inputId);if(!toggle || !input)return;toggle.addEventListener('click',()=>{const show=input.type==='password';input.type=show ? 'text':'password';toggle.innerHTML=show ? '<i class="bi bi-eye-slash"></i>':'<i class="bi bi-eye"></i>';});}function validateEmail(email){return/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);}function getPasswordStrength(password){let score=0;if(password.length >=8)score++;if(password.length >=12)score++;if(/[a-z]/.test(password)&&/[A-Z]/.test(password))score++;if(/\d/.test(password))score++;if(/[^a-zA-Z0-9]/.test(password))score++;return score;}function renderPasswordStrength(password,containerId){const container=document.getElementById(containerId);if(!container)return;if(!password){container.innerHTML='';return;}const score=getPasswordStrength(password);const labels=['','Weak','Fair','Good','Strong','Very Strong'];const colors=['','var(--error-color)','#f59e0b','#f59e0b','var(--accent-green)','var(--accent-green)'];const widths=['','20%','40%','60%','80%','100%'];container.innerHTML=` <div style="display:flex;gap:3px;margin-bottom:0.35rem;"> ${[1,2,3,4,5].map(i=> `<div style="flex:1;height:4px;border-radius:2px;background:${i <=score ? colors[score]:'var(--border-color)'};transition:background 0.3s;"></div>`).join('')}</div> <span style="font-size:0.75rem;color:${colors[score]};">${labels[score]}</span> `;}function showFieldError(inputId,errorId,msg){const input=document.getElementById(inputId);const error=document.getElementById(errorId);if(input)input.style.borderColor='var(--error-color)';if(error){error.textContent=msg;error.style.display='block';}}function clearFieldError(inputId,errorId){const input=document.getElementById(inputId);const error=document.getElementById(errorId);if(input)input.style.borderColor='';if(error)error.style.display='none';}function setButtonLoading(btnId,loading,originalText){const btn=document.getElementById(btnId);if(!btn)return;if(loading){btn.disabled=true;btn.innerHTML='<span class="auth-spinner"></span> Please wait...';}else{btn.disabled=false;btn.textContent=originalText;}}function showToast(msg,type){const existing=document.querySelector('.auth-toast');if(existing)existing.remove();const toast=document.createElement('div');toast.className=`auth-toast auth-toast-${type}`;toast.textContent=msg;document.body.appendChild(toast);setTimeout(()=> toast.classList.add('active'),10);setTimeout(()=>{toast.classList.remove('active');setTimeout(()=> toast.remove(),300);},4000);}